import cv2
import numpy as np

cap = cv2.VideoCapture('/app/example_video.mp4')
frames = []
for i in range(120):
    ret, frame = cap.read()
    if ret:
        frames.append(frame)
cap.release()

bg = frames[0].astype(np.float64)

# Analyze motion regions - find bounding boxes of moving areas
for i in [0, 5, 10, 20, 30, 40, 50, 60, 70, 80, 85, 90, 95, 100, 105, 110, 115]:
    diff = cv2.absdiff(frames[i].astype(np.float64), bg)
    gray_diff = cv2.cvtColor(diff.astype(np.uint8), cv2.COLOR_BGR2GRAY)
    _, thresh = cv2.threshold(gray_diff, 30, 255, cv2.THRESH_BINARY)

    contours, _ = cv2.findContours(thresh, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)

    total_area = 0
    y_coords = []
    x_coords = []
    for c in contours:
        area = cv2.contourArea(c)
        if area > 100:
            x, y, w, h = cv2.boundingRect(c)
            total_area += area
            for px in range(x, x+w):
                for py in range(y, y+h):
                    if thresh[py, px] > 0:
                        x_coords.append(px)
                        y_coords.append(py)

    if x_coords:
        print(f'Frame {i:3d}: area={total_area:6d}, y_range=[{min(y_coords)}-{max(y_coords)}], x_range=[{min(x_coords)}-{max(x_coords)}]')
    else:
        print(f'Frame {i:3d}: no motion detected')
" 2>&1"}

